// generatePassword: Returns 5 random alpha numeric characters from [A-Z, a-z0-9]. This will help to generate password for reset links.
function generatePassword() {

    const chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789'
    return Array(5).fill().map(() => chars[Math.floor(Math.random() * 62)]).join('')
}

// Generate an URL with the following format: https://www.domainname.com/?token=<token>
// When we call this function it takes the return value of generatePassword as the token and  returns the generated URL for password reset
function generateResetURL(token) {
    const baseUrl = 'https://www.domainname.com'

    // In this function we are returning URL with the format: https://www.domainname.com/?token=<token>
    return `${baseUrl}/?token=${token}`
}

// Usage of the function
generateResetURL(generatePassword())